package edu.training.library.docs;

import javax.imageio.ImageIO;
import java.awt.*;
import java.awt.geom.RoundRectangle2D;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

final class DiagramFactory {
    private static final Color INK=new Color(31,41,55), MUTED=new Color(100,116,139), TEAL=new Color(18,103,106),
            GREEN=new Color(65,139,103), GOLD=new Color(201,151,63), SURFACE=new Color(247,249,250), LINE=new Color(203,213,225);
    private static final Font NORMAL=new Font("Microsoft YaHei UI",Font.PLAIN,18), BOLD=new Font("Microsoft YaHei UI",Font.BOLD,19);
    private DiagramFactory(){}

    static void generate(Path dir)throws IOException{
        Files.createDirectories(dir);
        architecture(dir.resolve("architecture.png"));
        modules(dir.resolve("modules.png"));
        er(dir.resolve("er-diagram.png"));
        flow(dir.resolve("borrow-flow.png"));
        login(dir.resolve("ui-login.png"));
        main(dir.resolve("ui-main.png"));
        tests(dir.resolve("test-summary.png"));
    }

    private static Graphics2D canvas(BufferedImage image){Graphics2D g=image.createGraphics();g.setRenderingHint(RenderingHints.KEY_ANTIALIASING,RenderingHints.VALUE_ANTIALIAS_ON);g.setColor(Color.WHITE);g.fillRect(0,0,image.getWidth(),image.getHeight());g.setStroke(new BasicStroke(2));return g;}
    private static void save(BufferedImage image,Graphics2D g,Path path)throws IOException{g.dispose();ImageIO.write(image,"png",path.toFile());}
    private static void box(Graphics2D g,int x,int y,int w,int h,String title,List<String> lines,Color accent){g.setColor(Color.WHITE);g.fill(new RoundRectangle2D.Double(x,y,w,h,12,12));g.setColor(LINE);g.draw(new RoundRectangle2D.Double(x,y,w,h,12,12));g.setColor(accent);g.fillRoundRect(x,y,8,h,8,8);g.setFont(BOLD);g.setColor(INK);g.drawString(title,x+24,y+32);g.setFont(NORMAL);g.setColor(MUTED);int yy=y+62;for(String line:lines){g.drawString(line,x+24,yy);yy+=28;}}
    private static void arrow(Graphics2D g,int x1,int y1,int x2,int y2){g.setColor(MUTED);g.setStroke(new BasicStroke(2.5f));g.drawLine(x1,y1,x2,y2);double a=Math.atan2(y2-y1,x2-x1);int s=10;Polygon p=new Polygon();p.addPoint(x2,y2);p.addPoint((int)(x2-s*Math.cos(a-.5)),(int)(y2-s*Math.sin(a-.5)));p.addPoint((int)(x2-s*Math.cos(a+.5)),(int)(y2-s*Math.sin(a+.5)));g.fillPolygon(p);}
    private static void route(Graphics2D g,int[]...points){g.setColor(MUTED);g.setStroke(new BasicStroke(2.5f));for(int n=0;n<points.length-2;n++)g.drawLine(points[n][0],points[n][1],points[n+1][0],points[n+1][1]);int[] a=points[points.length-2],b=points[points.length-1];arrow(g,a[0],a[1],b[0],b[1]);}
    private static void title(Graphics2D g,String text){g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,28));g.setColor(INK);g.drawString(text,40,48);}

    private static void architecture(Path path)throws IOException{BufferedImage i=new BufferedImage(1400,720,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);title(g,"图书馆借阅管理系统分层架构");box(g,70,105,300,180,"表示层 Swing",List.of("登录与角色导航","表格、表单、操作反馈","管理员 / 读者工作台"),TEAL);box(g,545,105,310,180,"业务服务层",List.of("LibraryService","事务与业务规则","输入校验、权限边界"),GREEN);box(g,1030,105,300,180,"数据访问层",List.of("LibraryRepository","预编译 SQL","领域对象映射"),GOLD);arrow(g,370,195,545,195);arrow(g,855,195,1030,195);box(g,340,390,320,180,"JDBC 与事务",List.of("短连接、提交与回滚","行锁保护库存","PBKDF2 密码校验"),TEAL);box(g,750,390,320,180,"关系数据库",List.of("H2 零配置演示","MySQL 8.4 正式部署","7 张核心业务表"),GOLD);arrow(g,1030,285,900,390);arrow(g,660,480,750,480);g.setFont(NORMAL);g.setColor(MUTED);g.drawString("同进程方法调用",420,180);g.drawString("JDBC",685,465);save(i,g,path);}
    private static void modules(Path path)throws IOException{BufferedImage i=new BufferedImage(1400,780,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);title(g,"功能模块关系图");box(g,535,92,330,120,"用户与权限",List.of("登录、注册、资料、借阅证"),TEAL);String[] names={"图书管理","馆藏查询","借阅管理","预约管理","罚款管理","统计分析"};String[] desc={"新增 / 修改 / 删除 / 分类","书名 / 作者 / 出版社 / 库存","借阅 / 归还 / 续借 / 历史","预约 / 取消 / 到馆提醒","超期计算 / 缴费状态","热门排行 / 库存概览"};int[][] pos={{80,330},{480,330},{880,330},{80,555},{480,555},{880,555}};for(int n=0;n<names.length;n++){box(g,pos[n][0],pos[n][1],350,130,names[n],List.of(desc[n]),n%3==0?GREEN:n%3==1?GOLD:TEAL);arrow(g,700,212,pos[n][0]+175,pos[n][1]);}save(i,g,path);}
    private static void er(Path path)throws IOException{BufferedImage i=new BufferedImage(1500,900,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);title(g,"核心数据 E-R 关系图");box(g,60,120,300,160,"users 用户",List.of("PK id","username / role","card_status"),TEAL);box(g,600,90,300,160,"books 图书",List.of("PK id  FK category_id","isbn / title / author","total / available"),GREEN);box(g,1120,120,300,130,"categories 分类",List.of("PK id","name"),GOLD);box(g,100,400,320,190,"loans 借阅",List.of("PK id","FK user_id / book_id","due_at / returned_at","renew_count / status"),TEAL);box(g,570,410,330,180,"reservations 预约",List.of("PK id","FK user_id / book_id","expires_at / status","notified"),GREEN);box(g,1020,430,320,170,"fines 罚款",List.of("PK id","FK loan_id / user_id","amount / status","paid_at"),GOLD);arrow(g,210,280,250,400);arrow(g,700,250,350,400);arrow(g,240,280,650,410);arrow(g,700,250,730,410);arrow(g,1270,250,900,170);route(g,new int[]{300,590},new int[]{300,650},new int[]{960,650},new int[]{1020,565});route(g,new int[]{60,200},new int[]{25,200},new int[]{25,735},new int[]{1380,735},new int[]{1380,515},new int[]{1340,515});g.setFont(NORMAL);g.setColor(MUTED);g.drawString("1:N",185,345);g.drawString("1:N",455,310);g.drawString("1:N",455,375);g.drawString("1:N",730,335);g.drawString("1:N",760,680);g.drawString("1:N",1360,380);g.drawString("1:N",1010,145);save(i,g,path);}
    private static void flow(Path path)throws IOException{BufferedImage i=new BufferedImage(1500,760,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);title(g,"借阅与归还核心流程");String[] s={"选择读者和图书","校验借阅证 / 罚款","校验上限与重复借阅","锁定库存并检查可借数","创建借阅记录","归还并恢复库存","计算逾期费用","唤醒最早预约"};int x=70,y=120;for(int n=0;n<s.length;n++){Color c=n<4?TEAL:n<6?GREEN:GOLD;box(g,x,y,300,95,String.valueOf(n+1),List.of(s[n]),c);if(n<3){arrow(g,x+300,y+48,x+360,y+48);x+=360;}else if(n==3){arrow(g,x+150,y+95,x+150,y+175);y+=175;}else if(n<7){arrow(g,x,y+48,x-60,y+48);x-=360;}}save(i,g,path);}
    private static void login(Path path)throws IOException{BufferedImage i=new BufferedImage(1400,820,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);g.setColor(TEAL);g.fillRect(0,0,650,820);g.setColor(Color.WHITE);g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,54));g.drawString("馆藏通",110,330);g.setFont(new Font("Microsoft YaHei UI",Font.PLAIN,22));g.drawString("借阅、预约与馆藏管理工作台",110,380);g.setColor(Color.WHITE);g.fillRect(650,0,750,820);g.setColor(INK);g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,32));g.drawString("登录系统",820,170);g.setFont(NORMAL);g.drawString("用户名",820,250);field(g,820,270,410,54,"reader");g.drawString("密码",820,365);field(g,820,385,410,54,"•••••••••");g.setColor(TEAL);g.fillRoundRect(820,485,410,56,8,8);g.setColor(Color.WHITE);g.setFont(BOLD);g.drawString("登 录",990,521);g.setColor(MUTED);g.setFont(NORMAL);g.drawString("注册读者账号",960,590);save(i,g,path);}
    private static void field(Graphics2D g,int x,int y,int w,int h,String value){g.setColor(SURFACE);g.fillRoundRect(x,y,w,h,7,7);g.setColor(LINE);g.drawRoundRect(x,y,w,h,7,7);g.setFont(NORMAL);g.setColor(MUTED);g.drawString(value,x+16,y+34);}
    private static void main(Path path)throws IOException{BufferedImage i=new BufferedImage(1500,900,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);g.setColor(Color.WHITE);g.fillRect(0,0,1500,80);g.setColor(INK);g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,23));g.drawString("馆藏通  |  图书馆借阅管理系统",30,48);g.setFont(NORMAL);g.drawString("演示读者 · 读者",1240,46);g.setColor(SURFACE);g.fillRect(0,80,1500,820);String[] nav={"总览","馆藏检索","我的借阅","预约管理","罚款记录","统计分析"};g.setColor(Color.WHITE);g.fillRect(20,100,190,760);for(int n=0;n<nav.length;n++){if(n==1){g.setColor(new Color(224,242,241));g.fillRoundRect(35,150+n*58,160,42,7,7);}g.setColor(n==1?TEAL:INK);g.setFont(n==1?BOLD:NORMAL);g.drawString(nav[n],60,178+n*58);}g.setColor(INK);g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,28));g.drawString("馆藏检索",245,150);field(g,830,115,145,44,"书名");field(g,990,115,260,44,"Java");g.setColor(TEAL);g.fillRoundRect(1265,115,85,44,7,7);g.setColor(Color.WHITE);g.setFont(BOLD);g.drawString("查询",1288,145);String[] heads={"ISBN","书名","作者","出版社","分类","馆藏","可借","位置"};int[] widths={160,245,190,235,110,80,80,110};int xx=245;g.setColor(new Color(226,232,240));g.fillRect(245,200,1210,48);g.setFont(BOLD);g.setColor(INK);for(int n=0;n<heads.length;n++){g.drawString(heads[n],xx+10,231);xx+=widths[n];}String[][] rows={{"9787111213826","Java编程思想","Bruce Eckel","机械工业出版社","计算机","5","4","A-01"},{"9787115428028","深入理解计算机系统","Randal E. Bryant","人民邮电出版社","计算机","3","3","A-02"},{"9787020002207","红楼梦","曹雪芹","人民文学出版社","文学","4","2","B-01"}};g.setFont(NORMAL);for(int r=0;r<rows.length;r++){int yy=290+r*62;g.setColor(r%2==0?Color.WHITE:SURFACE);g.fillRect(245,248+r*62,1210,62);g.setColor(INK);xx=245;for(int n=0;n<rows[r].length;n++){g.drawString(rows[r][n],xx+10,yy);xx+=widths[n];}}save(i,g,path);}
    private static void tests(Path path)throws IOException{BufferedImage i=new BufferedImage(1400,650,BufferedImage.TYPE_INT_RGB);Graphics2D g=canvas(i);title(g,"自动化测试执行结果");int x=120,y=140,w=1050,h=70;g.setColor(new Color(226,232,240));g.fillRoundRect(x,y,w,h,10,10);g.setColor(GREEN);g.fillRoundRect(x,y,w,h,10,10);g.setColor(Color.WHITE);g.setFont(new Font("Microsoft YaHei UI",Font.BOLD,24));g.drawString("9 / 9 通过",x+450,y+45);box(g,120,300,300,150,"功能测试",List.of("9 个用例","9 个通过"),TEAL);box(g,550,300,300,150,"失败 / 错误",List.of("0 个失败","0 个错误"),GREEN);box(g,980,300,300,150,"通过率",List.of("100%","构建可交付"),GOLD);g.setColor(MUTED);g.setFont(NORMAL);g.drawString("执行命令：mvn test    测试框架：JUnit 5    数据库：H2 内存库（MySQL 兼容模式）",220,540);save(i,g,path);}
}
